sql:
SELECT review_id, UPPER(review_frequency)
FROM review_frequency
WHERE review_id = 1;

SELECT DISTINCT client_id
FROM deposits
WHERE deposit_method = 'online' AND deposit_date BETWEEN DATE('now', '-1 year') AND DATE('now');

SELECT "investment_objective", "risk_tolerance"
FROM "investment_objectives"
WHERE "client_id" = 2;

SELECT COUNT(client_id) AS num_clients
FROM wallet_share
WHERE wallet_share >= 0.25;

SELECT COUNT(*)
FROM advisor
WHERE years_of_experience > 5;

SELECT client_id, COUNT(objective_id) AS total_objectives
FROM investment_objectives
GROUP BY client_id;

SELECT advisor_id
FROM advisor_clients
WHERE client_id = 1;

SELECT first_name, last_name
FROM advisor
WHERE advisor_rating = (
    SELECT MAX(advisor_rating)
    FROM advisor
);

SELECT likelihood_score
FROM likelihood_scores
WHERE score_range = '02 - 25 to 50';

